```plantuml
@startuml

abstract class BookFactory <<A>> {
    +GetBook()
}

abstract class Book <<A>> {
    +BookCategory
    +Page
    +Author
}

class FantasticFactory <<C>> {
    -_page
    -_author
    +FantasticFactory()
}

class ScienceFictionFactory <<C>> {
    -_page
    -_author
    +ScienceFictionFactory()
}

class FantasticBook <<C>> {
    -_bookCategory
    -_page
    -_author
    +FantasticBook()
}

class ScienceFictionBook <<C>> {
    -_bookCategory
    -_page
    -_author
    +ScienceFictionBook()
}

FantasticFactory --|> BookFactory
ScienceFictionFactory --|> BookFactory

FantasticBook --|> Book
ScienceFictionBook --|> Book

FantasticFactory ..> FantasticBook
ScienceFictionFactory ..> ScienceFictionBook

@enduml
